--
-- Table structure for table `caipiao_game_platform`
--

DROP TABLE IF EXISTS `caipiao_game_platform`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_game_platform` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(20) NOT NULL COMMENT 'mã nhà cung cấp',
  `name` varchar(50) NOT NULL COMMENT 'tên nhà cung cấp',
  `slot_name` varchar(50) DEFAULT NULL COMMENT 'danh mục slot gametên',
  `live_name` varchar(50) DEFAULT NULL COMMENT 'danh mục casino trực tuyếntên',
  `chess_name` varchar(50) DEFAULT NULL COMMENT 'danh mục game bàitên',
  `fishing_name` varchar(50) DEFAULT NULL COMMENT 'danh mục bắn cátên',
  `type` varchar(20) NOT NULL COMMENT 'loại trò chơi live=casino trực tuyến, sport=thể thao, slot=slot game, chess=game bài',
  `kind` varchar(20) NOT NULL DEFAULT 'third' COMMENT 'nhà cung cấp Loại: local=, third=',
  `icon` varchar(255) DEFAULT '' COMMENT 'Biểu tượng',
  `mobile_icon` varchar(255) DEFAULT NULL,
  `banner` varchar(255) DEFAULT NULL,
  `mobile_banner` varchar(255) DEFAULT NULL,
  `slot_banner` varchar(255) DEFAULT NULL COMMENT 'banner slot game',
  `live_banner` varchar(255) DEFAULT NULL COMMENT 'banner casino trực tuyến',
  `chess_banner` varchar(255) DEFAULT NULL COMMENT 'banner game bài',
  `fishing_banner` varchar(255) DEFAULT NULL COMMENT 'banner bắn cá',
  `status` varchar(20) DEFAULT 'online' COMMENT 'Trạng thái online=trực tuyến, offline=ngoại tuyến, maintain=',
  `hot` tinyint(1) DEFAULT '0' COMMENT 'phổ biến',
  `recommend` tinyint(1) DEFAULT '0' COMMENT 'đề xuất',
  `sort` int(11) DEFAULT '0' COMMENT 'Sắp xếp',
  `api_url` varchar(255) DEFAULT '' COMMENT 'địa chỉ API',
  `api_key` varchar(255) DEFAULT '' COMMENT 'AP I',
  `api_secret` varchar(255) DEFAULT '' COMMENT 'AP I',
  `created_at` int(11) NOT NULL,
  `updated_at` int(11) DEFAULT '0',
  `api_provider` varchar(20) DEFAULT 'NG' COMMENT 'AP I: N G, W G',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_code` (`code`),
  KEY `idx_type` (`type`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=111 DEFAULT CHARSET=utf8mb4 COMMENT='游戏平台Bảng';
/*!40101 SET character_set_client = @saved_cs_client */;

